import{_ as t,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F06_存貨與債務穩定度審計.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F06_存貨與債務穩定度審計.md"}'),o={name:"審計報告庫/財務審計/3105_穩懋/20260503/F06_存貨與債務穩定度審計.md"};function e(n,a,s,h,d,_){return l(),i("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f06-存貨與債務穩定度審計-財務審計專家-審計報告" tabindex="-1">F06: 存貨與債務穩定度審計 - 財務審計專家 審計報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-財務審計專家-審計報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？分析存貨水位與債務結構，判定庫存跌價風險與償債能力。</p></blockquote><h2 id="🎯-專家直斷-52-字" tabindex="-1">🎯 專家直斷（52 字） <a class="header-anchor" href="#🎯-專家直斷-52-字" aria-label="Permalink to &quot;🎯 專家直斷（52 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：存貨 $4.98B 穩定（原料佔 70% 屬常態），流動比 248%、速動比 163%，現金 $7.07B 覆蓋短債無虞，去槓桿顯著。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-130-字" tabindex="-1">📊 診斷評級（130 字） <a class="header-anchor" href="#📊-診斷評級-130-字" aria-label="Permalink to &quot;📊 診斷評級（130 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：存貨 $4,979M（-2.6%），原料 70%、製成品僅 8%。長借從 $20.03B 降至 $12.33B（-38.5%），負債比 31.6%。庫存跌價回升 $100M。</li><li><strong>診斷見解</strong>：存貨水位穩定去化壓力低，負債去化顯著，利息保障改善。資產負債表結構穩健、流動性充裕。</li></ul><h2 id="🔍-答詢詳解-419-字" tabindex="-1">🔍 答詢詳解（419 字） <a class="header-anchor" href="#🔍-答詢詳解-419-字" aria-label="Permalink to &quot;🔍 答詢詳解（419 字）&quot;">​</a></h2><h3 id="存貨組成與去化效率-原料驅動型庫存結構" tabindex="-1">存貨組成與去化效率：原料驅動型庫存結構 <a class="header-anchor" href="#存貨組成與去化效率-原料驅動型庫存結構" aria-label="Permalink to &quot;存貨組成與去化效率：原料驅動型庫存結構&quot;">​</a></h3><ul><li><strong>核心重點</strong>：存貨 $4,979M：原料 $3,496M（70%）、WIP $1,065M（21%）、製成品 $418M（8%）。週轉天數 136 天較 2023 年改善。</li><li><strong>深度見解</strong>：製成品僅月營收 3%，出貨順暢。跌價回升 $100M 佐證品質改善。</li></ul><h3 id="償債能力-現金覆蓋充足-去槓桿加速" tabindex="-1">償債能力：現金覆蓋充足，去槓桿加速 <a class="header-anchor" href="#償債能力-現金覆蓋充足-去槓桿加速" aria-label="Permalink to &quot;償債能力：現金覆蓋充足，去槓桿加速&quot;">​</a></h3><ul><li><strong>核心重點</strong>：現金 $7,067M 遠高於流動負債 $5,865M（120.5%）。長借從 $20.03B 降至 $12.33B，利息從 $795M 降至 $675M（-15.1%）。</li><li><strong>深度見解</strong>：流動比 135%→248%，速動比 95%→163%，負債比 50.9%→31.6%，去槓桿成效顯著。</li></ul><h3 id="營運週期與現金循環" tabindex="-1">營運週期與現金循環 <a class="header-anchor" href="#營運週期與現金循環" aria-label="Permalink to &quot;營運週期與現金循環&quot;">​</a></h3><ul><li><strong>核心重點</strong>：CCC 從 508 天降至 406 天（-20.1%），主因 DPO 從 135 天擴至 186 天。</li><li><strong>深度見解</strong>：DPO 擴張反映談判力增強，惟需留意供應鏈關係。</li></ul><h2 id="💡-專家評析-372-字-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（372 字，≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-372-字-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（372 字，≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>存貨週轉天數偏長，下行週期壓力仍存</strong>：以年報 COGS 計算，存貨週轉天數約 136-151 天（約 4.5-5 個月），雖屬晶圓代工產業特性，但在終端需求快速反轉時仍存跌價風險。2024 年即曾提列 NT$235M 存貨跌價損失。若 2026 年手機 PA 需求再現修正，原料庫存 NT$3.5B（佔存貨 70%）可能面臨減值壓力。</p></li><li><p><strong>長期借款 NT$12.33B 仍為現金流固定負擔</strong>：雖已大幅去槓桿，但長期借款仍達 NT$12.33B，每年利息支出 NT$675M（2025 年），相當於營業利益 NT$715M 的 94.4%，幾乎吃掉全部營益。若產能利用率再度下滑導致營益萎縮，利息覆蓋率將快速惡化。</p></li><li><p><strong>DPO 擴張至 186 天潛藏供應鏈關係風險</strong>：應付天數從 135 天擴至 186 天，意味穩懋積欠供應商款項的時間拉長。雖短期有利營運現金，但長期可能導致關鍵原料供應商（如磊晶片廠）調整出貨條件或提高報價，間接推升 COGS。若供應鏈出現瓶頸，原料庫存 NT$3.5B 能否及時轉換為產能將受考驗。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (inventory_check 3105 2023 2025)</li><li>原始數據：FinMind TaiwanStockBalanceSheet、TaiwanStockFinancialStatements</li><li>年報 PDF：2025_Q4_3105_合併.pdf（存貨附註 p.7-8、借款資料 p.20-22、流動性資料 p.8）</li><li>查詢參數：stock_id=3105, start=2023-01-01, end=2025-12-31</li><li>關鍵核對碼：CurRatio 2025=248%, QuickRatio=163%, 長借NT$12.33B, 負債比31.6%, 存貨NT$4,979M</li></ul>',19)])])}const $=t(o,[["render",e]]);export{u as __pageData,$ as default};
